  ('islands-e3452428-moex-00095', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '依公務員懲戒法規定，關於停職之敘述，下列何者錯誤？ 公務員依刑事訴訟程序被羈押或通緝者，當然停職 懲戒法庭對於移送之懲戒案件，認為情節重大，有先行停止職務之必要者，得裁定停職 主管機關認所屬公務員違失情節重大，在移送監察院審查或懲戒法庭審理前，得依職權停止其職務 公務員在停職中所為之職務上行為，不生效力', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
